#include <bits/stdc++.h>using namespace std; int main() {    int t;    cin >> t;    while (t--) {        int x, k;        cin >> x >> k;        if (x % k != 0) {            cout << 1 << endl << x << endl;        }        else {            for (int i = x - 1; i >= 0; i --) {                if (i % k != 0 && (x - i) % k != 0) {                    cout << 2 << endl << i << " " << x - i << endl;                    break;                }            }        }    }    return 0;}